// Get the agent output
const inputData = $input.first().json;

// Extract the output field (which contains the JSON string)
let rawOutput = inputData.output || inputData.text || '';

// Try to parse the JSON
let parsedData = {};

try {
  // Parse the JSON string
  parsedData = JSON.parse(rawOutput);
} catch (e) {
  // If parsing fails, try to extract whatever we can
  parsedData = {
    run_scheduled: false,
    scheduled_time: 'N/A',
    weather_summary: 'Error parsing weather data',
    recommended_trail: {
      name: 'N/A',
      miles: 'N/A',
      elevation: 'N/A',
      estimated_time: 'N/A',
      shade_level: 'N/A'
    },
    reasoning: 'Unable to parse trail data'
  };
}

// Return the parsed data for the Gmail node
return [{ json: parsedData }];
